import java.io.IOException;
import javax.servlet.http.*;
import org.owasp.encoder.Encode;

public class XssSecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        response.setContentType("text/html");

        // Encode user input before writing it to the response
        String encodedUserInput = Encode.forHtml(userInput);

        response.getWriter().write("<h1>User Input:</h1>");
        response.getWriter().write(encodedUserInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
